import{_ as e,o as a,c as n,a0 as l}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Roles Explained","description":"","frontmatter":{},"headers":[],"relativePath":"roles/overview.md","filePath":"roles/overview.md"}'),r={name:"roles/overview.md"};function s(d,t,i,o,c,g){return a(),n("div",null,[...t[0]||(t[0]=[l(`<h1 id="roles-explained" tabindex="-1">Roles Explained <a class="header-anchor" href="#roles-explained" aria-label="Permalink to &quot;Roles Explained&quot;">​</a></h1><p>Everyone in the Kingshot Event Tracker has a <strong>role</strong>. Your role decides what you can see, what you can change, and how far your reach extends. This page explains the five built‑in roles in plain language.</p><p>Throughout the app and these docs we use the names you see on screen: <strong>Supreme Admin</strong>, <strong>King</strong>, <strong>Alliance Leader</strong>, <strong>Co‑Leader</strong>, and <strong>Alliance Player</strong>.</p><h2 id="the-five-roles-at-a-glance" tabindex="-1">The five roles at a glance <a class="header-anchor" href="#the-five-roles-at-a-glance" aria-label="Permalink to &quot;The five roles at a glance&quot;">​</a></h2><p>Roles form a ladder, from the widest reach to the narrowest. Each one can do everything sensible within its <strong><a href="./../getting-started/glossary.html#scope">scope</a></strong> — global, one kingdom, or one alliance.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Supreme Admin      ── the whole platform (all kingdoms)</span></span>
<span class="line"><span>   └── King         ── one kingdom and its alliances</span></span>
<span class="line"><span>        └── Alliance Leader   ── one alliance</span></span>
<span class="line"><span>             └── Co-Leader     ── helps run one alliance</span></span>
<span class="line"><span>                  └── Alliance Player  ── views one alliance&#39;s data</span></span></code></pre></div><h3 id="supreme-admin" tabindex="-1">Supreme Admin <a class="header-anchor" href="#supreme-admin" aria-label="Permalink to &quot;Supreme Admin&quot;">​</a></h3><p>The top of the platform. Runs everything: all kingdoms and alliances, users, roles, subscription plans, and global settings. Some powerful controls (like managing subscription plans, suspending groups, and configuring support links) are <strong>Supreme‑Admin‑only</strong>, even for other admins. If you need something that no one else can do, this is who you ask.</p><h3 id="king-kingdom-admin" tabindex="-1">King (Kingdom Admin) <a class="header-anchor" href="#king-kingdom-admin" aria-label="Permalink to &quot;King (Kingdom Admin)&quot;">​</a></h3><p>Runs <strong>one kingdom</strong> and everything inside it: its alliances, players, events, imports, and the users they create. A King can grant premium plans to their alliances and manage their kingdom&#39;s data end to end — but cannot reach other kingdoms, and cannot do the Supreme‑Admin‑only things. Kings also have a special ownership rule about the users and alliances they created (see <a href="./protection-rules.html">Safety Rules</a>).</p><h3 id="alliance-leader" tabindex="-1">Alliance Leader <a class="header-anchor" href="#alliance-leader" aria-label="Permalink to &quot;Alliance Leader&quot;">​</a></h3><p>Runs <strong>one alliance</strong>. Manages that alliance&#39;s players, events, results, and imports, handles its reports, and looks after its subscription/usage through the <strong>My Alliance</strong> page. A Leader can accept or decline a premium plan offered by their King. Leaders can&#39;t see kingdom‑wide analytics or manage other alliances.</p><h3 id="co‐leader" tabindex="-1">Co‑Leader <a class="header-anchor" href="#co‐leader" aria-label="Permalink to &quot;Co‑Leader&quot;">​</a></h3><p>A leader&#39;s helper for <strong>one alliance</strong>. Can do the everyday tracking work — add and edit players, enter results, upload and review imports, file reports — but <strong>cannot delete</strong> things, manage settings, or view the audit logs. Think of it as &quot;hands‑on help, without the risky buttons.&quot;</p><h3 id="alliance-player" tabindex="-1">Alliance Player <a class="header-anchor" href="#alliance-player" aria-label="Permalink to &quot;Alliance Player&quot;">​</a></h3><p>A <strong>view‑only</strong> member. Can read the dashboards, analytics, and rewards they&#39;re allowed to see, and can file reports — but cannot add, edit, delete, or import anything. (Internally this role is called &quot;viewer,&quot; but the app labels it <strong>Alliance Player</strong> — that&#39;s the name to use.)</p><h2 id="what-each-role-can-do-quick-comparison" tabindex="-1">What each role can do (quick comparison) <a class="header-anchor" href="#what-each-role-can-do-quick-comparison" aria-label="Permalink to &quot;What each role can do (quick comparison)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ability</th><th style="text-align:center;">Supreme Admin</th><th style="text-align:center;">King</th><th style="text-align:center;">Alliance Leader</th><th style="text-align:center;">Co‑Leader</th><th style="text-align:center;">Alliance Player</th></tr></thead><tbody><tr><td>View dashboards &amp; analytics</td><td style="text-align:center;">✅ (all)</td><td style="text-align:center;">✅ (kingdom)</td><td style="text-align:center;">✅ (alliance)</td><td style="text-align:center;">✅ (alliance)</td><td style="text-align:center;">✅ (scoped)</td></tr><tr><td>Add / edit players</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>Delete / restore players</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Upload &amp; review imports</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>Delete imports / roll back</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manage events &amp; templates</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manual data entry</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>Recycle Bin (view)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Recycle Bin (purge permanently)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manage users &amp; assign roles</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (own creations)</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Manage roles &amp; permissions</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Approve registrations</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>View audit logs</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Request a subscription</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>Manage plans / suspend groups</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Grant premium to alliances</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (own kingdom)</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Accept / decline a grant offer</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ (own alliance)</td><td style="text-align:center;">✅ (own alliance)</td><td style="text-align:center;">—</td></tr></tbody></table><p>This is a summary — each area has its own detailed guide in later sections.</p><h2 id="a-note-on-custom-roles" tabindex="-1">A note on custom roles <a class="header-anchor" href="#a-note-on-custom-roles" aria-label="Permalink to &quot;A note on custom roles&quot;">​</a></h2><p>The five roles above are the <strong>built‑in</strong> ones. A Supreme Admin can also create <strong>custom roles</strong> with a hand‑picked set of permissions. If your kingdom uses custom roles, your exact abilities might not match a built‑in role precisely — but the <em>scope</em> idea still holds, and the app always tells you when you don&#39;t have access.</p><p>If you&#39;re ever unsure what you can do, the safest sources are the app itself (menu items you can see) and, when in doubt, whoever is one level up from you.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../getting-started/glossary.html#multiple-roles">Holding Multiple Roles</a> — combining assignments (detailed guide in a later section).</li><li><a href="./protection-rules.html">Safety Rules You&#39;ll Run Into</a> — the guardrails every admin should know.</li><li><a href="./../getting-started/access-denied.html">&quot;You don&#39;t have access&quot;</a> — when a role stops you.</li></ul>`,24)])])}const y=e(r,[["render",s]]);export{p as __pageData,y as default};
